// ─── Helpers ──────────────────────────────────────────────────────────────────

export function fmtY(v: number) {
  if (v === 0) return '0';
  if (v >= 1e9) return `${(v / 1e9).toFixed(1)}B`;
  if (v >= 1e6) return `${v / 1e6}M`;
  if (v >= 1e3) return `${(v / 1e3).toFixed(1)}K`;
  return String(v);
}

